import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Grid, Chip } from '@mui/material';
import response from './response.json';

interface CartSummary {
  itemCount: number;
  totalPrice: number;
  savings: number;
}

interface CartItem {
  name: string;
  price: number;
  quantity: number;
  savings: number;
}

interface CartData {
  cartSummary: CartSummary;
  items: CartItem[];
}

export default function Widget() {
  const cartData = response.data as CartData;
  const { cartSummary, items } = cartData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#FF5722' }}>
              E-Shop Cart Summary
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Total Items: {cartSummary.itemCount}
            </Typography>
            <Typography variant="body2" sx={{ color: '#FF5722' }}>
              Total Price: ${cartSummary.totalPrice.toFixed(2)}
            </Typography>
            <Typography variant="body2" sx={{ color: '#FFC107' }}>
              Savings: ${cartSummary.savings.toFixed(2)}
            </Typography>
          </Box>

          <Grid container spacing={1}>
            {items.map((item, index) => (
              <Grid item xs={12} key={index}>
                <Stack direction="row" justifyContent="space-between" alignItems="center">
                  <Box>
                    <Typography variant="body2" sx={{ fontWeight: 500 }}>
                      {item.name}
                    </Typography>
                    <Typography variant="caption" color="text.secondary">
                      Qty: {item.quantity}
                    </Typography>
                  </Box>
                  <Box textAlign="right">
                    <Typography variant="body2" sx={{ color: '#FF5722' }}>
                      ${item.price.toFixed(2)}
                    </Typography>
                    <Typography variant="caption" sx={{ color: '#FFC107' }}>
                      Savings: ${item.savings.toFixed(2)}
                    </Typography>
                  </Box>
                </Stack>
              </Grid>
            ))}
          </Grid>
        </Stack>
      </CardContent>
    </Card>
  );
}
